36	#[test]
37	fn wait_and_drop() {
38	    let wg = WaitGroup::new();
39	    let wg2 = WaitGroup::new();
40	    let (tx, rx) = mpsc::channel();
41	
42	    for _ in 0..THREADS {
43	        let wg = wg.clone();
44	        let wg2 = wg2.clone();
45	        let tx = tx.clone();
46	
47	        thread::spawn(move || {
48	            wg2.wait();
